(5,  '上海市',   '上海市',   '310000', 121.473701, 31.230416, 11, '/mock-images/city/shanghai.jpg',  '国际化大都市，外滩、陆家嘴天际线和迪士尼乐园构成传统与现代交融的都市景观。', 4.0, 98, 5, 1, NOW(), NOW()),
(6,  '重庆市',   '重庆市',   '500000', 106.551556, 29.563009, 10, '/mock-images/city/chongqing.jpg', '山城江城，洪崖洞夜景、长江索道和火锅文化是核心体验，地形独特立体感强。', 3.0, 95, 6, 1, NOW(), NOW());
